  {"type":"cloze","sentence":"Whether ZKPs mature ___ government identity is an open question.","a":"into","alts":["into"],"explain":"INTO"},
  {"type":"cloze","sentence":"Proof size is ___ constant in SNARKs.","a":"roughly","alts":["roughly","approximately"],"explain":"adv"},
