  {"type":"key_word","original":"You should read the security considerations section carefully.","key":"DESERVES","gap_template":"The security considerations section ___ careful reading.","a":"deserves","alts":["deserves"],"explain":"swap"},
  {"type":"key_word","original":"Implementations are required to verify signatures.","key":"MUST","gap_template":"Implementations ___ signatures.","a":"MUST verify","alts":["MUST verify"],"explain":"normative"},
  {"type":"key_word","original":"You may read the appendices selectively.","key":"OPTIONAL","gap_template":"Reading the appendices is ___ .","a":"optional","alts":["optional"],"explain":"adj"},
  {"type":"key_word","original":"It is essential to read RFCs normatively.","key":"NORMATIVELY","gap_template":"RFCs must be read ___ .","a":"normatively","alts":["normatively"],"explain":"adv"},
